    /**
     * Validates that a URL belongs to an allowed origin.
     * Checks scheme (must be HTTPS) and host against the allowlist.
     */
    private fun isAllowedOrigin(url: String?): Boolean {
        if (url.isNullOrBlank()) return false

        return try {
            val parsedUrl = URL(url)
            val scheme = parsedUrl.protocol
            val host = parsedUrl.host
            val port = if (parsedUrl.port == -1) parsedUrl.defaultPort else parsedUrl.port

            // Must be HTTPS
            if (scheme != "https") {
                Log.w(TAG, "Blocked non-HTTPS URL: $url")
                return false
            }

            val origin = "https://$host" + if (port != 443) ":$port" else ""
            val allowed = ALLOWED_ORIGINS.contains(origin)

            if (!allowed) {
                Log.w(TAG, "Blocked URL from disallowed origin: $origin")
            }

            allowed
        } catch (e: Exception) {
            Log.e(TAG, "Failed to parse URL for origin check: $url", e)
            false
        }
    }

    /**
     * Extracts the origin (scheme + host + port) from a URL.
     */
    private fun getOrigin(url: String?): String? {
        if (url.isNullOrBlank()) return null
        return try {
            val parsedUrl = URL(url)
            val port = if (parsedUrl.port == -1) parsedUrl.defaultPort else parsedUrl.port
            "https://${parsedUrl.host}" + if (port != 443) ":$port" else ""
        } catch (e: Exception) {
            null
        }
    }

    // ========================================================================
    // Rate Limiting
    // ========================================================================

    @Synchronized
    private fun checkRateLimit(): Boolean {
        val now = System.currentTimeMillis()
        bridgeCallTimestamps.removeAll { now - it > RATE_LIMIT_WINDOW_MS }
        if (bridgeCallTimestamps.size >= MAX_BRIDGE_CALLS_PER_MINUTE) {
            Log.w(TAG, "Bridge call rate limit exceeded")
            return false
        }
        bridgeCallTimestamps.add(now)
        return true
    }

    // ========================================================================
