    private fun validateAndConsumeNonce(nonce: String): Boolean {
        val timestamp = pendingRequests.remove(nonce) ?: return false
        // Nonces expire after 5 minutes
        return (System.currentTimeMillis() - timestamp) < 300_000L
    }

    // ========================================================================
