    private fun sendCallbackToWeb(callbackId: String, success: Boolean, data: String) {
        val sanitizedData = data.replace("\\", "\\\\")
            .replace("'", "\\'")
            .replace("\n", "\\n")
            .replace("\r", "\\r")

        val js = """
            (function() {
                if (window.__nativeBridgeCallbacks && window.__nativeBridgeCallbacks['$callbackId']) {
                    window.__nativeBridgeCallbacks['$callbackId']($success, '$sanitizedData');
                    delete window.__nativeBridgeCallbacks['$callbackId'];
                }
            })();
        """.trimIndent()

        runOnUiThread {
            webView.evaluateJavascript(js, null)
        }
    }

