        // Allow only alphanumeric, underscore, hyphen, dot
        val sanitized = key.replace(Regex("[^a-zA-Z0-9_\\-.]"), "")
        return if (sanitized.isNotBlank() && sanitized == key) sanitized else null
    }

    private fun sanitizeStorageValue(value: String): String? {
