    private inner class SecureWebViewClient : WebViewClient() {

        override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
            val url = request?.url?.toString() ?: return true

            // Only allow navigation to allowed origins
            if (isAllowedOrigin(url)) {
                return false // Allow WebView to load
            }

            // For external links, open in external browser (optional, or just block)
            Log.w(TAG, "Blocked navigation to disallowed URL: $url")

            // Optionally open in external browser for user-initiated navigations
            if (request.isForMainFrame && request.hasGesture()) {
                try {
                    val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                    startActivity(intent)
                } catch (e: Exception) {
                    Log.e(TAG, "Failed to open external URL", e)
                }
            }

            return true // Block loading in WebView
        }

        override fun shouldInterceptRequest(
            view: WebView?,
            request: WebResourceRequest?
        ): WebResourceResponse? {
            val url = request?.url?.toString() ?: return super.shouldInterceptRequest(view, request)

            // Block requests to non-allowed origins (subresources too)
            if (!isAllowedOrigin(url)) {
                Log.w(TAG, "Blocked subresource request to: $url")
                return WebResourceResponse("text/plain", "UTF-8", 403, "Forbidden", emptyMap(), null)
            }

            return super.shouldInterceptRequest(view, request)
        }

        override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
            super.onPageStarted(view, url, favicon)

            // Double-check origin on page load
            if (!isAllowedOrigin(url)) {
                Log.e(TAG, "Page started loading from disallowed origin: $url")
                view?.stopLoading()
                view?.loadUrl("about:blank")
                return
            }

            Log.d(TAG, "Page loading: $url")
        }

        override fun onPageFinished(view: WebView?, url: String?) {
            super.onPageFinished(view, url)

            // Inject CSP meta tag as additional defense
            val cspScript = """
                (function() {
                    var meta = document.createElement('meta');
                    meta.httpEquiv = 'Content-Security-Policy';
                    meta.content = "default-src 'self' https://app.example.com https://cdn.example.com; script-src 'self' https://app.example.com https://cdn.example.com; style-src 'self' 'unsafe-inline' https://cdn.example.com; img-src 'self' https://cdn.example.com data:; connect-src 'self' https://app.example.com; frame-src 'none'; object-src 'none';";
                    document.head.prepend(meta);
                })();
            """.trimIndent()

            view?.evaluateJavascript(cspScript, null)

            // Inject the bridge callback infrastructure
            val bridgeSetup = """
                (function() {
                    if (!window.__nativeBridgeCallbacks) {
                        window.__nativeBridgeCallbacks = {};
                    }
                    window.__registerNativeCallback = function(callbackId, callback) {
                        window.__nativeBridgeCallbacks[callbackId] = callback;
                    };
                })();
            """.trimIndent()

            view?.evaluateJavascript(bridgeSetup, null)
        }

        override fun onReceivedError(
            view: WebView?,
            request: WebResourceRequest?,
            error: WebResourceError?
        ) {
            super.onReceivedError(view, request, error)
            if (request?.isForMainFrame == true) {
                Log.e(TAG, "WebView error: ${error?.description} (code: ${error?.errorCode})")
            }
        }

        override fun onReceivedSslError(
            view: WebView?,
            handler: android.webkit.SslErrorHandler?,
            error: android.net.http.SslError?
        ) {
            // SECURITY: NEVER proceed on SSL errors. Always cancel.
            Log.e(TAG, "SSL error encountered: ${error?.primaryError}. Cancelling.")
            handler?.cancel()

            runOnUiThread {
                Toast.makeText(
                    this@SecureHybridActivity,
                    "Secure connection failed. Please check your network.",
                    Toast.LENGTH_LONG
                ).show()
            }
        }
    }

