    private inner class SecureWebChromeClient : WebChromeClient() {

        override fun onShowFileChooser(
            webView: WebView?,
            filePathCallback: ValueCallback<Array<Uri>>?,
            fileChooserParams: FileChooserParams?
        ): Boolean {
            // Cancel any existing callback
            fileUploadCallback?.onReceiveValue(null)
            fileUploadCallback = filePathCallback

            val acceptTypes = fileChooserParams?.acceptTypes ?: arrayOf()
            val isImageCapture = acceptTypes.any { it.startsWith("image/") }
                    && fileChooserParams?.isCaptureEnabled == true

            if (isImageCapture) {
                launchCameraForFileUpload()
            } else {
                launchFileChooser(fileChooserParams)
            }

            return true
        }

        override fun onPermissionRequest(request: PermissionRequest?) {
            request?.let { req ->
                val origin = req.origin.toString()
                if (!isAllowedOrigin(origin)) {
                    Log.w(TAG, "Denied WebView permission request from disallowed origin: $origin")
                    req.deny()
                    return
                }

                // Only grant camera/microphone if explicitly needed
                val grantedResources = req.resources.filter { resource ->
                    when (resource) {
                        PermissionRequest.RESOURCE_VIDEO_CAPTURE -> {
                            hasCameraPermission()
                        }
                        else -> false // Deny all other resource types
                    }
                }.toTypedArray()

                if (grantedResources.isNotEmpty()) {
                    runOnUiThread {
                        req.grant(grantedResources)
                    }
                } else {
                    req.deny()
                }
            }
        }

        override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
            if (BuildConfig.DEBUG) {
                Log.d(TAG, "WebView Console: ${consoleMessage?.message()} " +
                        "(${consoleMessage?.sourceId()}:${consoleMessage?.lineNumber()})")
            }
            return true
        }

        // Block popups
        override fun onCreateWindow(
            view: WebView?,
            isDialog: Boolean,
            isUserGesture: Boolean,
            resultMsg: android.os.Message?
        ): Boolean {
            return false
        }
    }

    // ========================================================================
    // Camera Helpers
    // ========================================================================

    private fun hasCameraPermission(): Boolean {
        return ContextCompat.checkSelfPermission(
            this, Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
    }

    private fun requestCameraPermission() {
        cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
    }

    @Throws(IOException::class)
    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
        return File.createTempFile("IMG_${timeStamp}_", ".jpg", storageDir)
    }

    private fun launchCameraForFileUpload() {
        if (!hasCameraPermission()) {
            requestCameraPermission()
            fileUploadCallback?.onReceiveValue(null)
            fileUploadCallback = null
            return
        }

        try {
            val photoFile = createImageFile()
            cameraImageUri = FileProvider.getUriForFile(
                this,
                "${packageName}.fileprovider",
                photoFile
            )

            val cameraIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
            }

            cameraLauncher.launch(cameraIntent)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to launch camera", e)
            fileUploadCallback?.onReceiveValue(null)
            fileUploadCallback = null
        }
    }

    private fun launchFileChooser(params: WebChromeClient.FileChooserParams?) {
        val intent = Intent(Intent.ACTION_GET_CONTENT).apply {
            addCategory(Intent.CATEGORY_OPENABLE)
            type = params?.acceptTypes?.firstOrNull() ?: "*/*"
        }
        fileChooserLauncher.launch(intent)
    }

    // ========================================================================
    // JavaScript Bridge Interface — MINIMAL SURFACE
    // ========================================================================

    /**
     * Secure JavaScript bridge with minimal exposed methods.
     *
     * Each method:
     * 1. Validates the calling origin via WebView URL check
     * 2. Checks rate limits
     * 3. Validates all input parameters
     * 4. Returns a nonce/callback ID for async operations
     *
     * Web usage example:
     *   const callbackId = NativeBridge.requestCameraCapture();
     *   window.__registerNativeCallback(callbackId, function(success, data) {
     *       console.log('Camera result:', success, data);
     *   });
     */
    inner class SecureBridgeInterface {

        /**
         * Validates that the bridge call is coming from an allowed origin.
         */
        private fun validateCallingOrigin(): Boolean {
            var currentUrl: String? = null
            runOnUiThread {
                currentUrl = webView.url
            }
            // Small delay to ensure we get the URL (bridge calls are on background thread)
            Thread.sleep(50)

            // Also check via the stored URL
            val url = currentUrl ?: webView.url
            if (!isAllowedOrigin(url)) {
                Log.e(TAG, "Bridge call from disallowed origin: $url")
                return false
            }
            return true
        }

        // ---- Camera Access ----

        /**
         * Requests camera capture. Returns a callback ID for async result.
         * Web code should register a callback with this ID.
         */
        @JavascriptInterface
        fun requestCameraCapture(): String {
            if (!validateCallingOrigin()) return ""
            if (!checkRateLimit()) return ""

            val nonce = generateNonce()

            runOnUiThread {
                if (!hasCameraPermission()) {
                    // Request permission first
                    AlertDialog.Builder(this@SecureHybridActivity)
                        .setTitle("Camera Permission")
                        .setMessage("The app needs camera access to take photos.")
                        .setPositiveButton("Allow") { _, _ ->
                            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                            sendCallbackToWeb(nonce, false, """{"error":"Permission requested, please try again"}""")
                        }
                        .setNegativeButton("Deny") { _, _ ->
                            sendCallbackToWeb(nonce, false, """{"error":"Camera permission denied"}""")
                        }
                        .show()
                    return@runOnUiThread
                }

                try {
                    val photoFile = createImageFile()
                    bridgeCameraImageUri = FileProvider.getUriForFile(
                        this@SecureHybridActivity,
                        "${packageName}.fileprovider",
                        photoFile
                    )

                    pendingCameraNonce = nonce

                    val cameraIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                        putExtra(MediaStore.EXTRA_OUTPUT, bridgeCameraImageUri)
                    }

                    bridgeCameraLauncher.launch(cameraIntent)
                } catch (e: Exception) {
                    Log.e(TAG, "Failed to launch camera for bridge", e)
                    sendCallbackToWeb(nonce, false, """{"error":"Camera launch failed"}""")
                }
            }

            return nonce
        }

        /**
         * Checks if camera permission is granted.
         */
        @JavascriptInterface
        fun isCameraAvailable(): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false
            return hasCameraPermission()
        }

        // ---- Secure Local Storage ----

        /**
         * Stores a key-value pair in encrypted local storage.
         * Returns true on success, false on validation failure.
         */
        @JavascriptInterface
        fun secureStorageSet(key: String, value: String): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false

            val sanitizedKey = sanitizeStorageKey(key)
            if (sanitizedKey == null) {
                Log.w(TAG, "Invalid storage key rejected: ${key.take(50)}")
                return false
            }

            val sanitizedValue = sanitizeStorageValue(value)
            if (sanitizedValue == null) {
                Log.w(TAG, "Storage value too large for key: $sanitizedKey")
                return false
            }

            // Check total entry count
            if (encryptedPrefs.all.size >= MAX_STORAGE_ENTRIES &&
                !encryptedPrefs.contains("app_$sanitizedKey")
            ) {
                Log.w(TAG, "Storage entry limit reached")
                return false
            }

            return try {
                // Prefix keys to namespace them
                encryptedPrefs.edit()
                    .putString("app_$sanitizedKey", sanitizedValue)
                    .apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Failed to write to encrypted storage", e)
                false
            }
        }

        /**
         * Retrieves a value from encrypted local storage.
         * Returns the value or empty string if not found.
         */
        @JavascriptInterface
        fun secureStorageGet(key: String): String {
            if (!validateCallingOrigin()) return ""
            if (!checkRateLimit()) return ""

            val sanitizedKey = sanitizeStorageKey(key)
            if (sanitizedKey == null) {
                Log.w(TAG, "Invalid storage key rejected: ${key.take(50)}")
                return ""
            }

            return try {
                encryptedPrefs.getString("app_$sanitizedKey", "") ?: ""
            } catch (e: Exception) {
                Log.e(TAG, "Failed to read from encrypted storage", e)
                ""
            }
        }

        /**
         * Removes a value from encrypted local storage.
         */
        @JavascriptInterface
        fun secureStorageRemove(key: String): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false

            val sanitizedKey = sanitizeStorageKey(key)
            if (sanitizedKey == null) return false

            return try {
                encryptedPrefs.edit()
                    .remove("app_$sanitizedKey")
                    .apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Failed to remove from encrypted storage", e)
                false
            }
        }

        /**
         * Clears all app-namespaced entries from encrypted storage.
         */
        @JavascriptInterface
        fun secureStorageClear(): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false

            return try {
                val editor = encryptedPrefs.edit()
                encryptedPrefs.all.keys
                    .filter { it.startsWith("app_") }
                    .forEach { editor.remove(it) }
                editor.apply()
                true
            } catch (e: Exception) {
                Log.e(TAG, "Failed to clear encrypted storage", e)
                false
            }
        }

        // ---- Push Notifications ----

        /**
         * Requests notification permission (Android 13+).
         * Returns a callback ID for the async result.
         */
        @JavascriptInterface
        fun requestNotificationPermission(): String {
            if (!validateCallingOrigin()) return ""
            if (!checkRateLimit()) return ""

            val nonce = generateNonce()

            runOnUiThread {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                    val permission = Manifest.permission.POST_NOTIFICATIONS
                    if (ContextCompat.checkSelfPermission(
                            this@SecureHybridActivity, permission
                        ) == PackageManager.PERMISSION_GRANTED
                    ) {
                        sendCallbackToWeb(nonce, true, """{"granted":true}""")
                    } else {
                        notificationPermissionLauncher.launch(permission)
                        // Note: In production, you'd track this nonce and resolve
                        // it in the permission result callback
                        sendCallbackToWeb(nonce, true, """{"granted":"pending"}""")
                    }
                } else {
                    // Pre-Android 13, notifications are allowed by default
                    sendCallbackToWeb(nonce, true, """{"granted":true}""")
                }
            }

            return nonce
        }

        /**
         * Shows a local notification. Validates the payload strictly.
         * Accepts a JSON string with "title" and "body" fields.
         */
        @JavascriptInterface
        fun showLocalNotification(payloadJson: String): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false

            return try {
                val payload = JSONObject(payloadJson)

                if (!validateNotificationPayload(payload)) {
                    Log.w(TAG, "Invalid notification payload rejected")
                    return false
                }

                val title = payload.getString("title")
                val body = payload.getString("body")

                // Check notification permission on Android 13+
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                    if (ContextCompat.checkSelfPermission(
                            this@SecureHybridActivity,
                            Manifest.permission.POST_NOTIFICATIONS
                        ) != PackageManager.PERMISSION_GRANTED
                    ) {
                        Log.w(TAG, "Notification permission not granted")
                        return false
                    }
                }

                runOnUiThread {
                    val notificationManager =
                        getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager

                    val notification = NotificationCompat.Builder(
                        this@SecureHybridActivity,
                        NOTIFICATION_CHANNEL_ID
                    )
                        .setSmallIcon(android.R.drawable.ic_dialog_info)
                        .setContentTitle(title)
                        .setContentText(body)
                        .setPriority(NotificationCompat.PRIORITY_DEFAULT)
                        .setAutoCancel(true)
                        .build()

                    val notificationId = (System.currentTimeMillis() % Int.MAX_VALUE).toInt()
                    notificationManager.notify(notificationId, notification)
                }

                true
            } catch (e: JSONException) {
                Log.e(TAG, "Invalid JSON in notification payload", e)
                false
            } catch (e: Exception) {
                Log.e(TAG, "Failed to show notification", e)
                false
            }
        }

        /**
         * Checks if notification permission is granted.
         */
        @JavascriptInterface
        fun isNotificationPermissionGranted(): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false

            return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                ContextCompat.checkSelfPermission(
                    this@SecureHybridActivity,
                    Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED
            } else {
                true
            }
        }

        // ---- Device Info (limited) ----

        /**
         * Returns minimal, non-sensitive device info for the web app.
         */
        @JavascriptInterface
        fun getDeviceInfo(): String {
            if (!validateCallingOrigin()) return "{}"
            if (!checkRateLimit()) return "{}"

            return try {
                JSONObject().apply {
                    put("platform", "android")
                    put("sdkVersion", Build.VERSION.SDK_INT)
                    put("appVersion", BuildConfig.VERSION_NAME)
                    put("isDebug", BuildConfig.DEBUG)
                }.toString()
            } catch (e: Exception) {
                "{}"
            }
        }

        // ---- Haptic Feedback ----

        /**
         * Triggers a short haptic feedback.
         */
        @JavascriptInterface
        fun hapticFeedback(): Boolean {
            if (!validateCallingOrigin()) return false
            if (!checkRateLimit()) return false

            return try {
                runOnUiThread {
                    webView.performHapticFeedback(
                        android.view.HapticFeedbackConstants.VIRTUAL_KEY
                    )
                }
                true
            } catch (e: Exception) {
                false
            }
        }
    }

    // ========================================================================
    // Back Navigation
    // ========================================================================

    @Deprecated("Deprecated in Java")
    override fun onBackPressed() {
        if (webView.canGoBack()) {
            // Only go back if the previous URL is also in an allowed origin
            val backList = webView.copyBackForwardList()
            if (backList.currentIndex > 0) {
                val previousItem = backList.getItemAtIndex(backList.currentIndex - 1)
                if (isAllowedOrigin(previousItem.url)) {
                    webView.goBack()
                    return
                }
            }
        }
        super.onBackPressed()
    }

    // ========================================================================
    // Lifecycle
    // ========================================================================

    override fun onResume() {
        super.onResume()
        webView.onResume()
    }

    override fun onPause() {
        super.onPause()
        webView.onPause()
    }

    override fun onDestroy() {
        webView.apply {
            removeJavascriptInterface(BRIDGE_NAME)
            stopLoading()
            clearHistory()
            clearCache(true)
            loadUrl("about:blank")
            removeAllViews()
            destroy()
        }
        super.onDestroy()
    }
}

